(function(){var d=document,fired=false;function swap(){if(fired)return;fired=true;var links=d.querySelectorAll('link[data-wpmgr-href]');for(var i=0;i<links.length;i++){var l=links[i];l.setAttribute('href',l.getAttribute('data-wpmgr-href'));l.removeAttribute('data-wpmgr-href');}var olds=d.querySelectorAll('script[data-wpmgr-src],script[data-wpmgr-method]');for(var j=0;j<olds.length;j++){(function(o){var s=d.createElement('script');var src=o.getAttribute('data-wpmgr-src');for(var k=0;k<o.attributes.length;k++){var a=o.attributes[k];if(a.name==='data-wpmgr-src'||a.name==='data-wpmgr-method'||a.name==='type')continue;s.setAttribute(a.name,a.value);}if(src){s.src=src;}else{s.text=o.textContent||'';}o.parentNode.replaceChild(s,o);})(olds[j]);}cleanup();}function cleanup(){EV.forEach(function(e){window.removeEventListener(e,swap,OPT);});}var EV=['mousemove','keydown','touchstart','wheel','scroll'],OPT={passive:true};EV.forEach(function(e){window.addEventListener(e,swap,OPT);});if('requestIdleCallback'in window){requestIdleCallback(function(){setTimeout(swap,3000);},{timeout:6000});}else{setTimeout(swap,5000);}})();
